PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE protein (
	prot_id INTEGER NOT NULL, 
	prot_accession VARCHAR NOT NULL, 
	prot_seq VARCHAR NOT NULL, 
	is_canonical BOOLEAN, 
	struct_prot_type VARCHAR(8), 
	PRIMARY KEY (prot_id), 
	UNIQUE (prot_accession), 
	UNIQUE (prot_seq)
);
INSERT INTO protein VALUES(1,'PR0001','MADALGMIEVRGFVGMVEAADAMVKAAKVELIGYEKTGGGYVTAVVRGDVAAVKAATEAGQRAAERVGEVVAVHVIPRPHVNVDAALPLGRTPGMDKSA',1,'HEXAMER');
