CREATE TABLE xdatabase (
	xref_db_id INTEGER NOT NULL, 
	xref_db_name VARCHAR NOT NULL, 
	xref_db_type VARCHAR(9), 
	xref_db_url VARCHAR NOT NULL, 
	PRIMARY KEY (xref_db_id), 
	UNIQUE (xref_db_name), 
	UNIQUE (xref_db_url)
);
INSERT INTO xdatabase VALUES(1,'PDB','STRUCTURE','https://www.rcsb.org');
INSERT INTO xdatabase VALUES(2,'NCBI','SEQUENCE','https://www.ncbi.nlm.nih.gov');
INSERT INTO xdatabase VALUES(3,'Uniprot','SEQUENCE','https://www.uniprot.org');
INSERT INTO xdatabase VALUES(4,'NCBITAX','TAXONOMY','https://www.ncbi.nlm.nih.gov/taxonomy');
INSERT INTO xdatabase VALUES(5,'GO','FUNCTION','https://geneontology.org');
INSERT INTO xdatabase VALUES(6,'KO','FUNCTION','https://www.genome.jp/kegg/ko.html');
CREATE TABLE modification (
	modification_id INTEGER NOT NULL, 
	modification_description VARCHAR NOT NULL, 
	modification_type VARCHAR(12), 
	PRIMARY KEY (modification_id)
);
INSERT INTO modification VALUES(1,'trial, all fake info','DOMESTICATED');
CREATE TABLE name (
	name_id INTEGER NOT NULL, 
	prot_name VARCHAR NOT NULL, 
	PRIMARY KEY (name_id)
);
CREATE TABLE complex (
	complex_id INTEGER NOT NULL, 
	complex_accession VARCHAR NOT NULL, 
	complex_type VARCHAR NOT NULL, 
	is_active BOOLEAN, 
	is_exp_tested BOOLEAN, 
	PRIMARY KEY (complex_id), 
	UNIQUE (complex_accession)
);
CREATE TABLE interaction (
	interact_id INTEGER NOT NULL, 
	interact_type VARCHAR NOT NULL, 
	interact_description VARCHAR, 
	PRIMARY KEY (interact_id), 
	UNIQUE (interact_type, interact_description)
);
CREATE TABLE xref (
	xref_id INTEGER NOT NULL, 
	xref_acc_ext VARCHAR NOT NULL, 
	xref_db_id INTEGER NOT NULL, 
	PRIMARY KEY (xref_id), 
	UNIQUE (xref_acc_ext), 
	FOREIGN KEY(xref_db_id) REFERENCES xdatabase (xref_db_id)
);
INSERT INTO xref VALUES(1,'HOCH_RS28905',2);
INSERT INTO xref VALUES(2,'D0LID5',3);
INSERT INTO xref VALUES(3,'502025',4);
INSERT INTO xref VALUES(4,'6NLU',1);
INSERT INTO xref VALUES(5,'5DJB',1);
INSERT INTO xref VALUES(6,'51144',5);
INSERT INTO xref VALUES(7,'STM2462',2);
INSERT INTO xref VALUES(8,'P0A206',3);
INSERT INTO xref VALUES(9,'99287',4);
INSERT INTO xref VALUES(10,'K04024',5);
INSERT INTO xref VALUES(11,'31469',5);
CREATE TABLE cds (
	cds_id INTEGER NOT NULL, 
	cds_seq VARCHAR NOT NULL, 
	cds_accession VARCHAR NOT NULL, 
	prot_id INTEGER NOT NULL, 
	PRIMARY KEY (cds_id), 
	UNIQUE (cds_seq), 
	UNIQUE (cds_accession), 
	FOREIGN KEY(prot_id) REFERENCES protein (prot_id)
);
INSERT INTO cds VALUES(1,'','CD0001',1);
INSERT INTO cds VALUES(2,'','CD0002',2);
INSERT INTO cds VALUES(3,'','CD0003',2);
CREATE TABLE protein_name (
	prot_id INTEGER NOT NULL, 
	name_id INTEGER NOT NULL, 
	PRIMARY KEY (prot_id, name_id), 
	FOREIGN KEY(prot_id) REFERENCES protein (prot_id), 
	FOREIGN KEY(name_id) REFERENCES name (name_id)
);
CREATE TABLE isoforms (
	canonical_prot_id INTEGER NOT NULL, 
	isoform_prot_id INTEGER NOT NULL, 
	PRIMARY KEY (canonical_prot_id, isoform_prot_id), 
	FOREIGN KEY(canonical_prot_id) REFERENCES protein (prot_id), 
	FOREIGN KEY(isoform_prot_id) REFERENCES protein (prot_id)
);
CREATE TABLE protein_complex (
	prot_id INTEGER NOT NULL, 
	complex_id INTEGER NOT NULL, 
	is_essential BOOLEAN, 
	stoichiometry INTEGER, 
	PRIMARY KEY (prot_id, complex_id), 
	FOREIGN KEY(prot_id) REFERENCES protein (prot_id), 
	FOREIGN KEY(complex_id) REFERENCES complex (complex_id)
);
CREATE TABLE IF NOT EXISTS "Ppi" (
	ppi_id INTEGER NOT NULL, 
	interact_id INTEGER, 
	prot_id_1 INTEGER NOT NULL, 
	prot_id_2 INTEGER NOT NULL, 
	PRIMARY KEY (ppi_id), 
	UNIQUE (ppi_id), 
	FOREIGN KEY(interact_id) REFERENCES interaction (interact_id), 
	FOREIGN KEY(prot_id_1) REFERENCES protein (prot_id), 
	FOREIGN KEY(prot_id_2) REFERENCES protein (prot_id)
);
CREATE TABLE protein_xref (
	prot_id INTEGER NOT NULL, 
	xref_id INTEGER NOT NULL, 
	PRIMARY KEY (prot_id, xref_id), 
	FOREIGN KEY(prot_id) REFERENCES protein (prot_id), 
	FOREIGN KEY(xref_id) REFERENCES xref (xref_id)
);
INSERT INTO protein_xref VALUES(1,2);
INSERT INTO protein_xref VALUES(1,4);
INSERT INTO protein_xref VALUES(1,5);
INSERT INTO protein_xref VALUES(2,8);
CREATE TABLE origin_cds (
	origin_id INTEGER NOT NULL, 
	modified_id INTEGER NOT NULL, 
	PRIMARY KEY (origin_id, modified_id), 
	FOREIGN KEY(origin_id) REFERENCES cds (cds_id), 
	FOREIGN KEY(modified_id) REFERENCES cds (cds_id)
);
INSERT INTO origin_cds VALUES(2,3);
CREATE TABLE cds_xref (
	cds_id INTEGER NOT NULL, 
	xref_id INTEGER NOT NULL, 
	PRIMARY KEY (cds_id, xref_id), 
	FOREIGN KEY(cds_id) REFERENCES cds (cds_id), 
	FOREIGN KEY(xref_id) REFERENCES xref (xref_id)
);
INSERT INTO cds_xref VALUES(1,1);
INSERT INTO cds_xref VALUES(1,3);
INSERT INTO cds_xref VALUES(1,6);
INSERT INTO cds_xref VALUES(3,7);
INSERT INTO cds_xref VALUES(3,9);
INSERT INTO cds_xref VALUES(3,10);
INSERT INTO cds_xref VALUES(3,11);
CREATE TABLE cds_modification (
	cds_id INTEGER NOT NULL, 
	modification_id INTEGER NOT NULL, 
	PRIMARY KEY (cds_id, modification_id), 
	FOREIGN KEY(cds_id) REFERENCES cds (cds_id), 
	FOREIGN KEY(modification_id) REFERENCES modification (modification_id)
);
INSERT INTO cds_modification VALUES(3,1);
CREATE TABLE ppi_complex (
	ppi_id INTEGER NOT NULL, 
	complex_id INTEGER NOT NULL, 
	PRIMARY KEY (ppi_id, complex_id), 
	FOREIGN KEY(ppi_id) REFERENCES "Ppi" (ppi_id), 
	FOREIGN KEY(complex_id) REFERENCES complex (complex_id)
);
COMMIT;
